      "find": "    if parts.len() < 2 {
        return Err("invalid record");
    }
",
      "replace": "    if parts.len() != 2 {
        return Err("invalid record");
    }
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Updated the record parser to require exactly two comma-separated fields, so malformed records with extra fields are now rejected and tests pass."
}

