  "bug_category": "aggregation_reporting",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the reporting logic in src/lib.rs so the tests pass. The summary should aggregate only positive amounts by region, skip regions whose final total is zero, and order rows by total descending with region name ascending as a tiebreaker.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "weekly_region_sales_report_filters_zeroes"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Sale<'a> {
    pub region: &'a str,
    pub amount: i32,
}

pub fn sales_report(rows: &[Sale<'_>]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for row in rows {
        *totals.entry(row.region).or_insert(0) += row.amount;
    }

    let mut items: Vec<(&str, i32)> = totals.into_iter().collect();
    items.sort_by(|a, b| a.0.cmp(b.0));

    items
        .into_iter()
        .map(|(region, total)| format!("{}:{}", region, total))
        .collect::<Vec<_>>()
        .join("\n")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn aggregates_positive_amounts_only_and_sorts_by_total_then_name() {
        let rows = [
            Sale { region: "west", amount: 5 },
            Sale { region: "east", amount: 7 },
            Sale { region: "west", amount: -2 },
            Sale { region: "north", amount: 7 },
            Sale { region: "east", amount: 0 },
            Sale { region: "south", amount: 1 },
        ];

        assert_eq!(sales_report(&rows), "east:7\nnorth:7\nwest:5\nsouth:1");
    }

    #[test]
    fn omits_regions_with_zero_final_total_after_filtering() {
        let rows = [
            Sale { region: "east", amount: -3 },
            Sale { region: "west", amount: 0 },
            Sale { region: "north", amount: 4 },
        ];

        assert_eq!(sales_report(&rows), "north:4");
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "pub fn sales_report(rows: &[Sale<'_>]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for row in rows {
        *totals.entry(row.region).or_insert(0) += row.amount;
    }

    let mut items: Vec<(&str, i32)> = totals.into_iter().collect();
    items.sort_by(|a, b| a.0.cmp(b.0));

    items
        .into_iter()
        .map(|(region, total)| format!("{}:{}", region, total))
        .collect::<Vec<_>>()
        .join("\n")
}",
      "replace": "pub fn sales_report(rows: &[Sale<'_>]) -> String {
    let mut totals: BTreeMap<&str, i32> = BTreeMap::new();

    for row in rows {
        if row.amount > 0 {
            *totals.entry(row.region).or_insert(0) += row.amount;
        }
    }

    let mut items: Vec<(&str, i32)> = totals.into_iter().filter(|(_, total)| *total > 0).collect();
    items.sort_by(|a, b| b.1.cmp(&a.1).then_with(|| a.0.cmp(b.0)));

    items
        .into_iter()
        .map(|(region, total)| format!("{}:{}", region, total))
        .collect::<Vec<_>>()
        .join("\n")
}"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Fixed sales_report to ignore non-positive rows, omit zero-total regions, and sort report lines by total descending with region-name tiebreaks."
}

{
  "family": "patch_test_pass",
  "case_id": "ticket_lifecycle_reopen_resolution",
  "bug_category": "state_transitions",
  "difficulty": "hard",
  "user": "In the Rust crate at {project_root}, fix the ticket state transition logic in src/lib.rs so the tests pass. Keep the implementation compact and preserve the existing public API.",
  "expected_tool_sequence": ["read_file", "apply_patch", "cargo_test"],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "ticket_lifecycle"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
    Cancel,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub assignee: Option<&'static str>,
    pub resolution: Option<&'static str>,
    pub closed_at: Option<u64>,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::Open,
            assignee: None,
            resolution: None,
            closed_at: None,
        }
    }

    pub fn apply(&mut self, event: Event, actor: Option<&'static str>, now: u64) {
        match event {
            Event::Start => {
                if self.status == Status::Open {
                    self.status = Status::InProgress;
                    self.assignee = actor;
                }
            }
            Event::Resolve => {
                if self.status == Status::InProgress {
                    self.status = Status::Resolved;
                    self.resolution = Some("done");
                }
            }
            Event::Close => {
                if self.status == Status::Resolved {
                    self.status = Status::Closed;
                    self.closed_at = Some(now);
                }
            }
            Event::Reopen => {
                if self.status == Status::Closed {
                    self.status = Status::Open;
                }
            }
            Event::Cancel => {
                self.status = Status::Closed;
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::{Event, Status, Ticket};

    #[test]
    fn reopen_closed_ticket_clears_terminal_fields_and_returns_to_open() {
        let mut ticket = Ticket::new();
        ticket.apply(Event::Start, Some("alice"), 10);
        ticket.apply(Event::Resolve, Some("alice"), 20);
        ticket.apply(Event::Close, Some("alice"), 30);

        assert_eq!(ticket.status, Status::Closed);
        assert_eq!(ticket.resolution, Some("done"));
        assert_eq!(ticket.closed_at, Some(30));

        ticket.apply(Event::Reopen, Some("bob"), 40);

        assert_eq!(ticket.status, Status::Open);
        assert_eq!(ticket.assignee, None);
        assert_eq!(ticket.resolution, None);
        assert_eq!(ticket.closed_at, None);
    }

    #[test]
    fn cancel_only_works_before_closure_and_clears_context() {
        let mut ticket = Ticket::new();
        ticket.apply(Event::Start, Some("alice"), 1);
        ticket.apply(Event::Cancel, Some("alice"), 2);

        assert_eq!(ticket.status, Status::Closed);
        assert_eq!(ticket.assignee, None);
        assert_eq!(ticket.resolution, None);
        assert_eq!(ticket.closed_at, Some(2));

        let snapshot = ticket.clone();
        ticket.apply(Event::Cancel, Some("bob"), 3);
        assert_eq!(ticket, snapshot);
    }

    #[test]
    fn start_from_resolved_or_closed_does_not_change_ticket() {
        let mut resolved = Ticket::new();
        resolved.apply(Event::Start, Some("alice"), 1);
        resolved.apply(Event::Resolve, Some("alice"), 2);
        let before_resolved = resolved.clone();
        resolved.apply(Event::Start, Some("bob"), 3);
        assert_eq!(resolved, before_resolved);

        let mut closed = Ticket::new();
        closed.apply(Event::Start, Some("alice"), 1);
        closed.apply(Event::Resolve, Some("alice"), 2);
        closed.apply(Event::Close, Some("alice"), 3);
        let before_closed = closed.clone();
        closed.apply(Event::Start, Some("bob"), 4);
        assert_eq!(closed, before_closed);
    }

    #[test]
    fn closing_requires_resolution_but_preserves_resolution_data() {
        let mut ticket = Ticket::new();
        ticket.apply(Event::Close, Some("alice"), 5);
        assert_eq!(ticket.status, Status::Open);
        assert_eq!(ticket.closed_at, None);

        ticket.apply(Event::Start, Some("alice"), 6);
        ticket.apply(Event::Resolve, Some("alice"), 7);
        ticket.apply(Event::Close, Some("alice"), 8);

        assert_eq!(ticket.status, Status::Closed);
        assert_eq!(ticket.resolution, Some("done"));
        assert_eq!(ticket.closed_at, Some(8));
    }
}
"
  },
  "steps": [
    {
      "tool": "read_file",
      "file_path": "src/lib.rs"
    },
    {
      "tool": "apply_patch",
      "file_path": "src/lib.rs",
      "find": "            Event::Reopen => {
                if self.status == Status::Closed {
                    self.status = Status::Open;
                }
            }
            Event::Cancel => {
                self.status = Status::Closed;
            }
",
      "replace": "            Event::Reopen => {
                if self.status == Status::Closed {
                    self.status = Status::Open;
                    self.assignee = None;
                    self.resolution = None;
                    self.closed_at = None;
                }
            }
            Event::Cancel => {
                if self.status != Status::Closed {
                    self.status = Status::Closed;
                    self.assignee = None;
                    self.resolution = None;
                    self.closed_at = Some(now);
                }
            }
"
    },
    {
      "tool": "cargo_test",
      "expect_status": "success"
    }
  ],
  "final": "FINAL: Updated the ticket transition logic so reopening a closed ticket clears terminal state, and cancel now only closes non-closed tickets while clearing context and recording closure time. All tests pass."
}

