{
  "family": "patch_test_pass",
  "case_id": "config_layer_merge_override_enable_flag",
  "bug_category": "config_merge_precedence",
  "difficulty": "medium",
  "user": "In the Rust crate at {project_root}, fix the config merge logic in src/lib.rs so the layered precedence matches the tests: defaults should be the base, env should override defaults, and cli should override env, while Option fields only replace earlier values when they are Some. Then run the test suite.",
  "expected_tool_sequence": [
    "read_file",
    "apply_patch",
    "cargo_test"
  ],
  "expected_output": null,
  "files": {
    "Cargo.toml": "[package]
name = "config_layer_merge_override_enable_flag"
version = "0.1.0"
edition = "2021"

[lib]
path = "src/lib.rs"
",
    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Config {
    pub host: String,
    pub port: u16,
    pub tls: bool,
    pub token: Option<String>,
}

#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub tls: Option<bool>,
    pub token: Option<String>,
}

pub fn merge_config(defaults: &Config, env: &PartialConfig, cli: &PartialConfig) -> Config {
    Config {
        host: cli
            .host
            .clone()
            .or_else(|| env.host.clone())
            .unwrap_or_else(|| defaults.host.clone()),
        port: cli.port.or(env.port).unwrap_or(defaults.port),
        tls: env.tls.or(cli.tls).unwrap_or(defaults.tls),
        token: defaults
            .token
            .clone()
            .or_else(|| env.token.clone())
            .or_else(|| cli.token.clone()),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn base() -> Config {
        Config {
            host: "localhost".to_string(),
            port: 8080,
            tls: false,
            token: Some("default-token".to_string()),
        }
    }

    #[test]
    fn cli_has_highest_precedence() {
        let env = PartialConfig {
            host: Some("env.internal".to_string()),
            port: Some(9000),
            tls: Some(false),
            token: Some("env-token".to_string()),
        };
        let cli = PartialConfig {
            host: Some("cli.example.com".to_string()),
            port: Some(7000),
            tls: Some(true),
            token: Some("cli-token".to_string()),
        };

        let merged = merge_config(&base(), &env, &cli);
        assert_eq!(merged.host, "cli.example.com");
        assert_eq!(merged.port, 7000);
        assert!(merged.tls);
        assert_eq!(merged.token.as_deref(), Some("cli-token"));
    }

    #[test]
    fn env_fills_when_cli_missing() {
        let env = PartialConfig {
            host: Some("env.internal".to_string()),
            port: None,
            tls: Some(true),
            token: Some("env-token".to_string()),
        };
        let cli = PartialConfig {
            host: None,
            port: Some(7000),
            tls: None,
            token: None,
        };

        let merged = merge_config(&base(), &env, &cli);
        assert_eq!(merged.host, "env.internal");
        assert_eq!(merged.port, 7000);
        assert!(merged.tls);
        assert_eq!(merged.token.as_deref(), Some("env-token"));
    }

    #[test]
    fn defaults_remain_when_no_override_present() {
        let env = PartialConfig::default();
        let cli = PartialConfig::default();

        let merged = merge_config(&base(), &env, &cli);
