pub enum State {
    Draft,
    Review,
    Approved,
    Rejected,
    Published,
    Archived,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Submit,
    Approve,
    Reject,
    Revise,
    Publish,
    Archive,
    Restore,
}

pub fn apply_events(events: &[Event]) -> State {
    let mut state = State::Draft;

    for event in events {
        state = match (state, *event) {
            (State::Draft, Event::Submit) => State::Review,
            (State::Review, Event::Approve) => State::Approved,
            (State::Review, Event::Reject) => State::Rejected,
            (State::Rejected, Event::Revise) => State::Draft,
            (State::Approved, Event::Publish) => State::Published,
            (State::Published, Event::Archive) => State::Archived,
            (State::Archived, Event::Restore) => State::Draft,
            (_, Event::Archive) => State::Archived,
            (_, Event::Restore) => State::Draft,
            (_, _) => state,
        };
    }

    state
}

