    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    OnHold,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Pause,
    Resume,
    Resolve,
    Close,
    Reopen,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub assignee: Option<&'static str>,
    pub resolution: Option<&'static str>,
    pub closed_at: Option<u64>,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::Open,
            assignee: None,
            resolution: None,
            closed_at: None,
        }
    }

    pub fn apply(&mut self, event: Event, actor: Option<&'static str>, now: u64) -> bool {
        match event {
            Event::Start => {
                if self.status == Status::Open || self.status == Status::OnHold {
                    self.status = Status::InProgress;
                    self.assignee = actor.or(self.assignee);
                    true
                } else {
                    false
                }
            }
            Event::Pause => {
                if self.status == Status::InProgress {
                    self.status = Status::OnHold;
                    true
                } else {
                    false
                }
            }
            Event::Resume => {
                if self.status == Status::OnHold {
                    self.status = Status::InProgress;
                    true
                } else {
                    false
                }
            }
            Event::Resolve => {
                if self.status == Status::InProgress {
