    Manager,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    Comment,
    StartWork,
    Resolve,
    Reopen,
    Close,
}

pub fn allowed(state: TicketState, role: UserRole, action: Action) -> bool {
    match action {
        Action::Comment => true,
        Action::StartWork => matches!(state, TicketState::Open) && matches!(role, UserRole::Agent),
