    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    New,
    Assigned,
    InProgress,
    Paused,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub assignee: Option<&'static str>,
    pub resolution: Option<&'static str>,
    pub reopen_count: u8,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Open,
    Assign(&'static str),
    StartWork,
    Pause,
    Resume,
    Resolve(&'static str),
    Reopen,
    Close,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::New,
            assignee: None,
            resolution: None,
            reopen_count: 0,
        }
    }

    pub fn apply(&mut self, event: Event) {
        match event {
            Event::Open => {
                self.status = Status::New;
                self.assignee = None;
                self.resolution = None;
                self.reopen_count = 0;
            }
            Event::Assign(name) => {
                if self.status != Status::Closed {
                    self.assignee = Some(name);
                    if self.status == Status::New {
                        self.status = Status::Assigned;
                    }
                }
            }
            Event::StartWork => {
                if matches!(self.status, Status::Assigned | Status::Paused) {
                    self.status = Status::InProgress;
                }
            }
            Event::Pause => {
                if self.status == Status::InProgress {
                    self.status = Status::Paused;
                }
            }
            Event::Resume => {
                if self.status == Status::Paused {
                    self.status = Status::InProgress;
                }
            }
            Event::Resolve(note) => {
                if matches!(self.status, Status::InProgress | Status::Paused) {
                    self.status = Status::Resolved;
                    self.resolution = Some(note);
                }
            }
            Event::Reopen => {
                if matches!(self.status, Status::Resolved | Status::Closed) {
                    self.status = Status::Assigned;
                    self.reopen_count += 1;
                }
            }
            Event::Close => {
                if self.status == Status::Resolved {
                    self.status = Status::Closed;
                }
            }
        }
    }
}

