pub fn monthly_region_report(orders: &[Order]) -> String {
    let mut totals: BTreeMap<&str, BTreeMap<&str, i32>> = BTreeMap::new();

    for order in orders {
        if !order.shipped {
            continue;
        }
        *totals
            .entry(order.region)
            .or_default()
            .entry(order.month)
            .or_default() += order.amount;
