        DeliveryState::Queued => "pending",
        DeliveryState::Sent => "delivered",
        DeliveryState::Failed { retryable } => {
            if retryable {
                "retrying"
            } else {
                "failed"
            }
        }
        DeliveryState::Bounced => match channel {
            Channel::Email => "failed",
            Channel::Sms => "bounced",
            Channel::Push => "bounced",
        },
    }
}

