#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    Active,
    Paused,
    Done,
    Cancelled,
}

enum Event {
    Create(&'static str),
    Start(&'static str),
    Pause(&'static str),
    Resume(&'static str),
    Finish(&'static str),
    Cancel(&'static str),
    Reopen(&'static str),
}

fn apply(status: Option<Status>, event: &Event) -> Option<Status> {
    match (status, event) {
        (None, Event::Create(_)) => Some(Status::New),
        (Some(Status::New), Event::Start(_)) => Some(Status::Active),
        (Some(Status::Active), Event::Pause(_)) => Some(Status::Paused),
        (Some(Status::Paused), Event::Resume(_)) => Some(Status::Active),
        (Some(Status::Active), Event::Finish(_)) => Some(Status::Done),
        (Some(_), Event::Cancel(_)) => Some(Status::Cancelled),
        (Some(Status::Done), Event::Reopen(_)) => Some(Status::Done),
        _ => status,
    }
}

fn id_of(event: &Event) -> &'static str {
    match event {
        Event::Create(id)
        | Event::Start(id)
        | Event::Pause(id)
        | Event::Resume(id)
        | Event::Finish(id)
        | Event::Cancel(id)
        | Event::Reopen(id) => id,
    }
}

fn label(status: Status) -> &'static str {
    match status {
        Status::New => "new",
        Status::Active => "active",
        Status::Paused => "paused",
        Status::Done => "done",
        Status::Cancelled => "cancelled",
    }
}

fn main() {
    let events = vec![
        Event::Create("A"),
        Event::Start("A"),
        Event::Pause("A"),
        Event::Resume("A"),
        Event::Finish("A"),
        Event::Reopen("A"),
        Event::Create("B"),
        Event::Start("B"),
        Event::Pause("B"),
        Event::Cancel("B"),
        Event::Resume("B"),
        Event::Create("C"),
        Event::Start("C"),
        Event::Cancel("C"),
        Event::Reopen("C"),
        Event::Finish("C"),
    ];

    let mut states: BTreeMap<&'static str, Status> = BTreeMap::new();
    for event in &events {
        let id = id_of(event);
        let next = apply(states.get(id).copied(), event);
        if let Some(status) = next {
            states.insert(id, status);
        }
    }

    for (id, status) in states {
        println!("{}: {}", id, label(status));
    }
}
