    for (name, event) in events {
        let task = tasks.entry(name).or_default();
        apply(task, event);
    }

    let mut lines = Vec::new();
    for (name, task) in tasks {
        lines.push(format!(
            "{}: {} (done={} blocked={} aborted={})",
            name,
            status_name(task.status),
            task.done_count,
            task.blocked_count,
            task.aborted_count
        ));
    }

    print!("{}", lines.join("\n"));
}
