  "files": {
    "Cargo.toml": "[package]
name = "ticket_lifecycle_transition_summary"
version = "0.1.0"
edition = "2021"
",
    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum Status {
    New,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn as_str(&self) -> &'static str {
        match self {
            Status::New => "New",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
        }
    }
}

enum Event<'a> {
    Create(&'a str),
    Start(&'a str),
    Block(&'a str),
    Unblock(&'a str),
    Close(&'a str),
    Reopen(&'a str),
}

fn apply_event(state: &mut BTreeMap<String, Status>, event: Event<'_>) {
    match event {
        Event::Create(id) => {
            state.entry(id.to_string()).or_insert(Status::New);
        }
