    InProgress,
    Blocked,
    Resolved,
    Cancelled,
}

impl fmt::Display for Status {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let s = match self {
            Status::Open => "Open",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Resolved => "Resolved",
            Status::Cancelled => "Cancelled",
        };
        write!(f, "{}", s)
    }
}

#[derive(Clone, Copy)]
enum Event {
    Start,
    Block,
    Unblock,
    Resolve,
    Reopen,
    Cancel,
}

struct Ticket {
    id: &'static str,
    status: Status,
    valid: usize,
    invalid: usize,
    history: Vec<Status>,
}

impl Ticket {
    fn new(id: &'static str) -> Self {
        Self {
            id,
            status: Status::Open,
            valid: 0,
            invalid: 0,
            history: vec![Status::Open],
        }
    }

    fn apply(&mut self, event: Event) {
        let next = match (self.status, event) {
            (Status::Open, Event::Start) => Some(Status::InProgress),
            (Status::Open, Event::Block) => Some(Status::Blocked),
            (Status::Open, Event::Cancel) => Some(Status::Cancelled),
            (Status::InProgress, Event::Block) => Some(Status::Blocked),
            (Status::InProgress, Event::Resolve) => Some(Status::Resolved),
