    "src/lib.rs": "use std::cmp::Ordering;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Entry {
    pub name: &'static str,
    pub solved: u32,
    pub penalty: u32,
    pub last_submit: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ranked {
    pub rank: usize,
    pub name: &'static str,
    pub solved: u32,
    pub penalty: u32,
    pub last_submit: u32,
}

pub fn leaderboard(entries: &[Entry]) -> Vec<Ranked> {
    let mut items = entries.to_vec();
    items.sort_by(|a, b| {
        b.solved.cmp(&a.solved)
            .then_with(|| a.penalty.cmp(&b.penalty))
            .then_with(|| a.name.cmp(&b.name))
    });

    let mut out = Vec::with_capacity(items.len());
    let mut prev: Option<&Entry> = None;
    let mut rank = 1;

    for (i, e) in items.iter().enumerate() {
        if let Some(p) = prev {
            if p.solved != e.solved || p.penalty != e.penalty {
                rank = i + 1;
            }
        }
        out.push(Ranked {
            rank,
            name: e.name,
            solved: e.solved,
            penalty: e.penalty,
            last_submit: e.last_submit,
        });
        prev = Some(e);
    }

    out
}

