pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut best_by_name: HashMap<String, Player> = HashMap::new();
    for p in players {
        best_by_name
            .entry(p.name.clone())
            .and_modify(|cur| {
                if p.score > cur.score {
