",
    "src/lib.rs": "use std::collections::BTreeMap;

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Status {
    Shipped,
    Returned,
    Cancelled,
}

#[derive(Clone, Debug)]
pub struct Order {
    pub store: &'static str,
    pub amount_cents: i64,
    pub status: Status,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub struct StoreReport {
    pub store: String,
    pub shipped: usize,
    pub returned: usize,
    pub net_cents: i64,
}

pub fn build_report(orders: &[Order]) -> Vec<StoreReport> {
    let mut totals: BTreeMap<&str, (usize, usize, i64)> = BTreeMap::new();

    for order in orders {
        let entry = totals.entry(order.store).or_insert((0, 0, 0));
        match order.status {
            Status::Shipped => {
                entry.0 += 1;
                entry.2 += order.amount_cents;
            }
            Status::Returned => {
                entry.1 += 1;
                entry.2 -= order.amount_cents;
            }
            Status::Cancelled => {
                entry.0 += 1;
            }
        }
    }

    let mut rows: Vec<StoreReport> = totals
        .into_iter()
        .map(|(store, (shipped, returned, net_cents))| StoreReport {
            store: store.to_string(),
            shipped,
            returned,
            net_cents,
        })
        .collect();

    rows.sort_by(|a, b| a.store.cmp(&b.store));
    rows
}

