#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Action {
    Allow,
    Review,
    Challenge,
    Deny,
}

pub fn decide_action(event: Event) -> Action {
    match event {
        Event::Login {
            trusted_device,
            risk_score,
        } => {
            if trusted_device {
                Action::Allow
            } else if risk_score >= 80 {
                Action::Review
            } else {
