            if amount_cents >= 100_000 {
                Action::Review
            } else if international {
                Action::Review
            } else if flagged {
                Action::Challenge
            } else {
                Action::Allow
            }
        }
        Event::PasswordReset {
            has_2fa,
            requested_by_support,
        } => {
            if requested_by_support {
                Action::Allow
            } else if has_2fa {
                Action::Challenge
            } else {
                Action::Review
            }
        }
        Event::ApiKeyUse {
            scope_write,
            ip_allowlisted,
        } => {
            if scope_write || !ip_allowlisted {
                Action::Review
            } else {
                Action::Allow
            }
        }
    }
}

