pub enum Event {
    Connected { secure: bool },
    Message { urgent: bool, encrypted: bool },
    Closed { code: u16 },
    Retry { attempt: u8, after_error: bool },
}

pub fn plan(event: Event) -> Vec<&'static str> {
    let mut actions = Vec::new();
    match event {
        Event::Connected { secure } => {
            actions.push("open");
            if !secure {
                actions.push("handshake");
            }
        }
        Event::Message { urgent, encrypted } => {
            actions.push("store");
            if urgent {
                actions.push("queue");
            }
            if encrypted {
                actions.push("scan");
            }
        }
        Event::Closed { code } => {
            actions.push("close");
            if code >= 500 {
                actions.push("archive");
            }
        }
        Event::Retry {
            attempt,
            after_error,
        } => {
            if attempt > 3 {
                actions.push("retry");
                actions.push("backoff");
            } else if after_error {
                actions.push("retry");
                actions.push("notify");
            } else {
                actions.push("retry");
            }
        }
    }
    actions
}

