#[derive(Debug, Clone, Default)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub use_tls: Option<bool>,
}

pub fn merge_config(defaults: &Config, file: &PartialConfig, cli: &PartialConfig) -> Config {
    let mut merged = defaults.clone();

    if let Some(host) = &cli.host {
        merged.host = host.clone();
    } else if let Some(host) = &file.host {
        merged.host = host.clone();
    }

    if let Some(port) = file.port {
        merged.port = port;
    }
    if let Some(port) = cli.port {
        merged.port = port;
    }

    if let Some(use_tls) = cli.use_tls {
        merged.use_tls = use_tls;
    } else {
        merged.use_tls = defaults.use_tls;
    }

    merged
}

