    pub amount_cents: u32,
    pub paid: bool,
}

pub fn monthly_report(orders: &[Order]) -> String {
    let mut by_region: BTreeMap<&str, (u32, u32)> = BTreeMap::new();
    let mut total_count = 0u32;
    let mut total_revenue = 0u32;

    for order in orders {
        total_count += 1;
        total_revenue += order.amount_cents;
        let entry = by_region.entry(order.region).or_insert((0, 0));
        entry.0 += 1;
        entry.1 += order.amount_cents;
    }

    let mut rows: Vec<_> = by_region.into_iter().collect();
    rows.sort_by(|a, b| a.0.cmp(b.0));

    let mut out = String::new();
    for (region, (count, revenue)) in rows {
        out.push_str(&format!("{region}: {count} orders ${:.2}\n", revenue as f64 / 100.0));
    }
    out.push_str(&format!("TOTAL: {total_count} orders ${:.2}", total_revenue as f64 / 100.0));
    out
}

