pub struct Record {
    pub id: String,
    pub qty: Option<u32>,
    pub note: Option<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_idx, raw_line) in input.lines().enumerate() {
        let line = raw_line.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut qty = None;
        let mut note = None;

        for part in line.split(',') {
            let piece = part.trim();
            if piece.is_empty() {
                continue;
            }
            let Some((key, value)) = piece.split_once('=') else {
                return Err(format!("line {}: malformed field", line_idx + 1));
            };
            match key.trim() {
                "id" => id = Some(value.trim().to_string()),
                "qty" => {
                    let n = value.trim().parse::<u32>()
                        .map_err(|_| format!("line {}: invalid qty", line_idx + 1))?;
                    qty = Some(n);
                }
                "note" => note = Some(value.trim().to_string()),
                _ => {}
            }
        }

        out.push(Record {
            id: id.unwrap_or_default(),
            qty,
            note,
        });
    }
    Ok(out)
}

