        };
        let env = PartialConfig {
            endpoint: Some(String::new()),
            retries: Some(0),
            timeout_ms: Some(900),
            use_tls: Some(false),
        };

        let merged = merge_config(file, env, PartialConfig::default());

        assert_eq!(merged.endpoint, None);
        assert_eq!(merged.retries, 0);
        assert_eq!(merged.timeout_ms, 900);
