#[derive(Clone, Debug, PartialEq, Eq)]
pub enum Status {
    Completed,
    Pending,
    Refunded,
}

pub fn build_report(orders: &[Order], top_n: usize) -> String {
    let mut completed = 0usize;
    let mut refunded = 0usize;
    let mut revenue_cents = 0i64;
    let mut per_customer: Vec<(&'static str, i64)> = Vec::new();

    for order in orders {
        match order.status {
            Status::Completed => completed += 1,
            Status::Refunded => refunded += 1,
            Status::Pending => {}
        }

        revenue_cents += order.amount_cents;

        let mut found = false;
        for (name, total) in &mut per_customer {
            if *name == order.customer {
                *total += order.amount_cents;
                found = true;
                break;
            }
        }
        if !found {
            per_customer.push((order.customer, order.amount_cents));
        }
    }

    per_customer.sort_by(|a, b| b.1.cmp(&a.1));

    let mut out = format!(
        "completed={} refunded={} revenue=${}.{:02}",
        completed,
        refunded,
        revenue_cents / 100,
        revenue_cents.abs() % 100
    );

    let take_n = top_n.min(per_customer.len());
    for (idx, (name, cents)) in per_customer.into_iter().take(take_n).enumerate() {
        out.push_str(&format!("\n{}. {} ${}.{:02}", idx + 1, name, cents / 100, cents.abs() % 100));
    }

    out
}

