        assert_eq!(apply_events(&events), Status::Closed);
    }

    #[test]
    fn unrelated_events_do_not_change_state() {
        let events = [Event::Close, Event::Block, Event::Unblock];
        assert_eq!(apply_events(&events), Status::New);
    }
}
