#[derive(Debug, Clone, PartialEq, Eq)]
pub enum Setting<T> {
    Inherit,
    Set(T),
    Clear,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PartialConfig {
    pub host: Option<String>,
    pub port: Option<u16>,
    pub token: Setting<String>,
}

pub fn merge_config(defaults: &Config, env: &PartialConfig, cli: &PartialConfig) -> Config {
    let host = cli
        .host
        .clone()
        .or_else(|| env.host.clone())
        .unwrap_or_else(|| defaults.host.clone());

    let port = cli.port.or(env.port).unwrap_or(defaults.port);

    let token = match &cli.token {
        Setting::Set(value) => Some(value.clone()),
        Setting::Inherit => match &env.token {
            Setting::Set(value) => Some(value.clone()),
            Setting::Clear => None,
            Setting::Inherit => defaults.token.clone(),
        },
        Setting::Clear => defaults.token.clone(),
    };

    Config { host, port, token }
}

