    "src/lib.rs": "#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Record {
    pub id: String,
    pub qty: u32,
    pub active: bool,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();
    for (line_no, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut id = None;
        let mut qty = None;
        let mut active = None;
        let mut tags: Vec<String> = Vec::new();

        for field in line.split(';') {
            let mut parts = field.splitn(2, ':');
            let key = parts.next().unwrap_or("").trim();
            let value = parts.next().unwrap_or("").trim();
            if key.is_empty() {
                return Err(format!("line {}: empty field", line_no + 1));
            }
            match key {
                "id" => id = Some(value.to_string()),
                "qty" => {
                    qty = Some(
                        value
                            .parse::<u32>()
                            .map_err(|_| format!("line {}: invalid qty", line_no + 1))?,
                    )
                }
                "active" => active = Some(value == "true"),
                "tags" => {
                    tags = value
                        .split(',')
                        .filter(|s| !s.is_empty())
                        .map(|s| s.to_string())
                        .collect()
                }
                _ => {}
            }
        }

        let record = Record {
            id: id.ok_or_else(|| format!("line {}: missing id", line_no + 1))?,
            qty: qty.ok_or_else(|| format!("line {}: missing qty", line_no + 1))?,
            active: active.ok_or_else(|| format!("line {}: missing active", line_no + 1))?,
            tags,
        };
        out.push(record);
    }
    Ok(out)
}

