pub fn leaderboard(players: &[Player]) -> Vec<String> {
    let mut items = players.to_vec();
    items.sort_by(|a, b| {
        a.points
            .cmp(&b.points)
            .then_with(|| a.wins.cmp(&b.wins))
            .then_with(|| a.name.cmp(b.name))
