pub fn department_report(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, (u32, usize)> = BTreeMap::new();

    for entry in entries {
        let slot = totals.entry(entry.department).or_insert((0, 0));
        slot.0 += entry.hours;
