pub struct Player {
    pub name: &'static str,
    pub wins: u32,
    pub draws: u32,
    pub losses: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct RankedPlayer {
    pub rank: usize,
    pub name: &'static str,
    pub points: u32,
    pub goal_diff: i32,
}

fn points(p: &Player) -> u32 {
    p.wins * 3 + p.draws
}

fn goal_diff(p: &Player) -> i32 {
    p.wins as i32 - p.losses as i32
}

pub fn leaderboard(players: &[Player]) -> Vec<RankedPlayer> {
    let mut ordered: Vec<&Player> = players.iter().collect();
    ordered.sort_by(|a, b| {
        points(b)
            .cmp(&points(a))
            .then_with(|| a.name.cmp(b.name))
    });

    let mut out = Vec::with_capacity(ordered.len());
    let mut last_points = None;
    let mut rank = 0usize;

    for (idx, p) in ordered.into_iter().enumerate() {
        let pts = points(p);
        if Some(pts) != last_points {
            rank = idx + 1;
            last_points = Some(pts);
        }
        out.push(RankedPlayer {
            rank,
            name: p.name,
            points: pts,
            goal_diff: goal_diff(p),
        });
    }

    out
}

