pub struct Record {
    pub name: String,
    pub count: u32,
    pub active: bool,
    pub tags: Vec<String>,
}

pub fn parse_records(input: &str) -> Result<Vec<Record>, String> {
    let mut out = Vec::new();

    for (idx, raw) in input.lines().enumerate() {
        let line = raw.trim();
        if line.is_empty() {
            continue;
        }

        let mut name = None;
        let mut count = None;
        let mut active = None;
        let mut tags = Vec::new();

        for part in line.split(';') {
            let part = part.trim();
            if part.is_empty() {
                continue;
            }
            let (key, value) = part
                .split_once('=')
                .ok_or_else(|| format!("line {} malformed field", idx + 1))?;
            match key.trim() {
                "name" => name = Some(value.trim().to_string()),
                "count" => {
                    count = Some(
                        value
                            .trim()
                            .parse::<u32>()
                            .map_err(|_| format!("line {} invalid count", idx + 1))?,
                    )
                }
                "active" => {
                    active = Some(match value.trim() {
                        "true" => true,
                        "false" => false,
                        _ => return Err(format!("line {} invalid active", idx + 1)),
                    })
                }
                "tags" => {
                    tags = value
                        .split(',')
                        .map(|s| s.trim().to_string())
                        .filter(|s| !s.is_empty())
                        .collect();
                }
                _ => {}
            }
        }

        let rec = Record {
            name: name.ok_or_else(|| format!("line {} missing name", idx + 1))?,
            count: count.ok_or_else(|| format!("line {} missing count", idx + 1))?,
            active: active.ok_or_else(|| format!("line {} missing active", idx + 1))?,
            tags,
        };
        out.push(rec);
    }

    Ok(out)
}

