name = "ticket_lifecycle"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Status {
    Open,
    InProgress,
    Resolved,
    Closed,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Event {
    Start,
    Resolve,
    Close,
    Reopen,
    Cancel,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Ticket {
    pub status: Status,
    pub assignee: Option<&'static str>,
    pub resolution: Option<&'static str>,
    pub closed_at: Option<u64>,
}

impl Ticket {
    pub fn new() -> Self {
        Self {
            status: Status::Open,
            assignee: None,
            resolution: None,
            closed_at: None,
        }
    }

    pub fn apply(&mut self, event: Event, ts: u64) {
        match event {
            Event::Start => {
                if self.status == Status::Open {
                    self.status = Status::InProgress;
                }
            }
            Event::Resolve => {
                if matches!(self.status, Status::Open | Status::InProgress) {
                    self.status = Status::Resolved;
                    self.resolution = Some("fixed");
                }
            }
            Event::Close => {
                if self.status == Status::Resolved {
                    self.status = Status::Closed;
                    self.closed_at = Some(ts);
                }
            }
            Event::Reopen => {
                if matches!(self.status, Status::Resolved | Status::Closed) {
                    self.status = Status::Open;
                }
            }
            Event::Cancel => {
                self.assignee = None;
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn reopen_from_resolved_clears_resolution_and_keeps_closed_at_empty() {
        let mut t = Ticket::new();
        t.apply(Event::Start, 1);
        t.apply(Event::Resolve, 2);
        assert_eq!(t.status, Status::Resolved);
