fn build_report(items: &[Item]) -> String {
    let mut rows: Vec<(String, usize)> = items
        .iter()
        .flat_map(|item| item.tags.iter().map(move |tag| (item, *tag)))
        .filter(|(item, tag)| item.active || !tag.contains("skip"))
        .map(|(_, tag)| tag.to_string())
        .fold(Vec::<(String, usize)>::new(), |mut acc, tag| {
