#[derive(Clone, Copy)]
enum State {
    Open,
    InProgress,
    Closed,
}

impl State {
    fn as_str(&self) -> &'static str {
        match self {
            State::Open => "Open",
            State::InProgress => "InProgress",
            State::Closed => "Closed",
        }
    }
}

fn apply_event(state: State, event: &str) -> State {
    match event {
        "start" => State::InProgress,
        "resolve" => State::InProgress,
        "reopen" => State::Open,
        _ => state,
    }
}

fn main() {
    let events = [
        ("A", "start"),
        ("A", "resolve"),
        ("B", "start"),
        ("B", "reopen"),
        ("C", "resolve"),
    ];

    let mut states = BTreeMap::new();

    for (id, event) in events {
        let current = states.get(id).copied().unwrap_or(State::Open);
        let next = apply_event(current, event);
        states.insert(id, next);
    }

    for (id, state) in states {
        println!("{}:{}", id, state.as_str());
    }
}
