  "expected_output": "create item.txt [ok]
move item.txt -> archive/ [queued]
copy item.txt -> backup/ [skipped: same volume]
delete old.log [dry-run]
summary: ok=1 queued=1 skipped=1 dry-run=1",
  "files": {
    "Cargo.toml": "[package]
name = "dispatch_summary_enum_branch_recover_38"
version = "0.1.0"
edition = "2021"
",
    "src/main.rs": "enum Action {
    Create,
    Move,
    Copy,
    Delete,
}

enum Outcome {
    Ok,
    Queued,
    Skipped(&'static str),
    DryRun,
}

struct Command {
    action: Action,
    target: &'static str,
    dest: Option<&'static str>,
    simulate: bool,
    same_volume: bool,
}

fn execute(cmd: &Command) -> Outcome {
    match cmd.action {
        Action::Create => Outcome::Ok,
        Action::Move => {
            if cmd.simulate {
                Outcome::DryRun
            } else {
                Outcome::Queued
            }
        }
        Action::Copy => Outcome::Queued,
        Action::Delete => Outcome::Ok,
    }
}

fn render(cmd: &Command, out: &Outcome) -> String {
    match (cmd.action, out) {
        (Action::Create, Outcome::Ok) => format!("create {} [ok]", cmd.target),
        (Action::Move, Outcome::Queued) => format!("move {} -> {} [queued]", cmd.target, cmd.dest.unwrap_or("?")),
        (Action::Move, Outcome::DryRun) => format!("move {} [dry-run]", cmd.target),
        (Action::Copy, Outcome::Queued) => format!("copy {} -> {} [queued]", cmd.target, cmd.dest.unwrap_or("?")),
        (Action::Delete, Outcome::Ok) => format!("delete {} [ok]", cmd.target),
        (_, Outcome::Skipped(reason)) => format!("skip {} [{}]", cmd.target, reason),
        (_, Outcome::DryRun) => format!("noop {} [dry-run]", cmd.target),
        _ => format!("unknown {}", cmd.target),
    }
}

fn main() {
    let commands = [
        Command {
            action: Action::Create,
            target: "item.txt",
            dest: None,
            simulate: false,
            same_volume: false,
        },
        Command {
            action: Action::Move,
            target: "item.txt",
            dest: Some("archive/"),
            simulate: false,
            same_volume: false,
        },
        Command {
            action: Action::Copy,
            target: "item.txt",
            dest: Some("backup/"),
            simulate: false,
            same_volume: true,
        },
        Command {
            action: Action::Delete,
            target: "old.log",
            dest: None,
            simulate: true,
            same_volume: false,
        },
    ];

    let mut ok = 0;
    let mut queued = 0;
    let mut skipped = 0;
    let mut dry_run = 0;

    for cmd in commands.iter() {
        let out = execute(cmd);
        match out {
            Outcome::Ok => ok += 1,
            Outcome::Queued => queued += 1,
            Outcome::Skipped(_) => skipped += 1,
            Outcome::DryRun => dry_run += 1,
        }
        println!("{}", render(cmd, &out));
    }

    println!(
        "summary: ok={} queued={} skipped={} dry-run={}"
        , ok, queued, skipped, dry_run
    );
}
