    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum Status {
    New,
    Paid,
    Shipped,
    Canceled,
}

#[derive(Clone, Copy)]
enum Event {
    Create,
    Pay,
    Ship,
    Cancel,
}

fn apply(status: Option<Status>, event: Event) -> Option<Status> {
    match (status, event) {
        (None, Event::Create) => Some(Status::New),
        (Some(Status::New), Event::Pay) => Some(Status::Paid),
        (Some(Status::Paid), Event::Ship) => Some(Status::Shipped),
        (_, Event::Cancel) => Some(Status::Canceled),
        (s, _) => s,
    }
}

fn label(status: Status) -> &'static str {
    match status {
        Status::New => "New",
        Status::Paid => "Paid",
        Status::Shipped => "Shipped",
        Status::Canceled => "Canceled",
    }
}

fn main() {
    let events = [
        ("A", Event::Create),
        ("A", Event::Pay),
        ("A", Event::Cancel),
        ("B", Event::Create),
        ("B", Event::Cancel),
        ("B", Event::Pay),
        ("C", Event::Create),
        ("C", Event::Pay),
        ("C", Event::Ship),
        ("C", Event::Cancel),
    ];

    let mut orders: BTreeMap<&str, Status> = BTreeMap::new();

    for (id, event) in events {
        let next = apply(orders.get(id).copied(), event);
        if let Some(status) = next {
            orders.insert(id, status);
        }
    }

    for (id, status) in orders {
        println!("{}: {}", id, label(status));
    }
}
