#[derive(Clone, Copy)]
enum Status {
    Open,
    InProgress,
    Done,
}

fn apply(status: Status, event: &str) -> Status {
    match (status, event) {
        (Status::Open, "start") => Status::InProgress,
        (Status::InProgress, "resolve") => Status::Open,
        (Status::Done, "reopen") => Status::Done,
        (s, _) => s,
    }
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "open",
        Status::InProgress => "working",
        Status::Done => "done",
    }
}

fn main() {
    let events = [
        ("T1", "start"),
        ("T1", "resolve"),
        ("T2", "resolve"),
        ("T3", "start"),
        ("T3", "resolve"),
        ("T3", "reopen"),
        ("T3", "resolve"),
    ];

    let mut tickets: BTreeMap<&str, Status> = BTreeMap::new();
    for (id, event) in events {
        let current = tickets.get(id).copied().unwrap_or(Status::Open);
        let next = apply(current, event);
        tickets.insert(id, next);
    }

    for (id, status) in tickets {
        println!("{}:{}", id, label(status));
    }
}
