",
    "src/main.rs": "enum Channel {
    Api,
    Admin,
    Batch,
}

enum Action {
    Login,
    Export,
    Purge,
    Retry,
}

struct Event {
    channel: Channel,
    action: Action,
    urgent: bool,
}

enum Outcome {
    Accepted(u32),
    Rejected(u32),
    Review(u32),
}

fn evaluate(e: &Event) -> Outcome {
    match (&e.channel, &e.action, e.urgent) {
        (Channel::Api, Action::Login, _) => Outcome::Accepted(3),
        (Channel::Api, Action::Export, false) => Outcome::Accepted(2),
        (Channel::Api, Action::Export, true) => Outcome::Rejected(2),
        (Channel::Admin, Action::Purge, false) => Outcome::Accepted(5),
        (Channel::Admin, Action::Purge, true) => Outcome::Accepted(5),
        (Channel::Batch, Action::Retry, _) => Outcome::Rejected(4),
        (Channel::Batch, Action::Export, _) => Outcome::Review(1),
        (Channel::Admin, Action::Login, _) => Outcome::Rejected(1),
        _ => Outcome::Review(0),
    }
}

fn alert_tag(e: &Event) -> Option<&'static str> {
    match (&e.channel, &e.action, e.urgent) {
        (Channel::Api, Action::Login, true) => Some("login"),
        (Channel::Admin, Action::Purge, false) => Some("purge"),
        _ => None,
    }
}

fn main() {
    let events = [
        Event { channel: Channel::Api, action: Action::Login, urgent: true },
        Event { channel: Channel::Api, action: Action::Export, urgent: false },
        Event { channel: Channel::Admin, action: Action::Purge, urgent: true },
        Event { channel: Channel::Batch, action: Action::Retry, urgent: false },
        Event { channel: Channel::Batch, action: Action::Export, urgent: true },
    ];

    let mut accepted = 0;
    let mut rejected = 0;
    let mut review = 0;
    let mut login_alerts = 0;
    let mut purge_alerts = 0;

    for e in &events {
        match evaluate(e) {
            Outcome::Accepted(n) => accepted += n,
            Outcome::Rejected(n) => rejected += n,
            Outcome::Review(n) => review += n,
        }

        match alert_tag(e) {
            Some("login") => login_alerts += 1,
            Some("purge") => purge_alerts += 1,
            _ => {}
        }
    }

    println!("accepted={}", accepted);
    println!("rejected={}", rejected);
    println!("review={}", review);
    println!("alerts=login:{},purge:{}", login_alerts, purge_alerts);
}
