#[derive(Clone, Default)]
struct Ticket {
    status: &'static str,
    assignee: &'static str,
    attempts: u32,
}

enum Event {
    Open(&'static str),
    Assign(&'static str),
    Fail,
    Resolve,
    Close,
    Block,
    Reopen,
}

fn apply(t: &mut Ticket, e: &Event) {
    match e {
        Event::Open(owner) => {
            t.status = "open";
            t.assignee = owner;
        }
        Event::Assign(owner) => {
            t.assignee = owner;
        }
        Event::Fail => {
            t.attempts += 1;
            t.status = "open";
        }
        Event::Resolve => {
            t.status = "closed";
        }
        Event::Close => {
            t.status = "closed";
        }
        Event::Block => {
            t.status = "blocked";
        }
        Event::Reopen => {
            t.status = "open";
            t.attempts = 0;
        }
    }
}

