    let log = vec![
        ("A", Event::Open("amy")),
        ("A", Event::Fail),
        ("A", Event::Resolve),
        ("A", Event::Assign("zoe")),
        ("A", Event::Close),
        ("A", Event::Reopen),
        ("A", Event::Assign("-")),
        ("A", Event::Fail),
        ("A", Event::Resolve),
        ("A", Event::Close),
        ("B", Event::Open("bob")),
        ("B", Event::Fail),
        ("B", Event::Block),
        ("B", Event::Reopen),
        ("B", Event::Fail),
        ("C", Event::Open("kim")),
        ("C", Event::Assign("lee")),
        ("C", Event::Block),
    ];

    let mut tickets: BTreeMap<&str, Ticket> = BTreeMap::new();
    for (id, event) in &log {
        let t = tickets.entry(id).or_default();
        apply(t, event);
    }

    let mut out = Vec::new();
    for (id, t) in tickets {
        out.push(format!(
            "{}: {} assignee={} attempts={}",
            id, t.status, t.assignee, t.attempts
        ));
    }
    print!("{}", out.join("\n"));
}
