  "files": {
    "Cargo.toml": "[package]
name = "ticket_state_transitions_recover"
version = "0.1.0"
edition = "2021"
",
    "src/main.rs": "#[derive(Clone, Copy)]
enum Status {
    Open,
    Pending,
    OnHold,
    Closed,
}

enum Event {
    Assign,
    CustomerReply,
    AgentReply,
    AgentNote,
    PutOnHold,
    Resume,
    Resolve,
}

fn next_status(status: Status, event: Event) -> Status {
    match event {
        Event::Assign => match status {
            Status::Open => Status::Pending,
            other => other,
        },
        Event::CustomerReply => match status {
            Status::Pending | Status::OnHold | Status::Closed => Status::Open,
            other => other,
        },
        Event::AgentReply => match status {
            Status::Open => Status::Pending,
            other => other,
        },
        Event::AgentNote => match status {
            Status::Closed => Status::Open,
            other => other,
        },
        Event::PutOnHold => match status {
            Status::Pending | Status::Open => Status::OnHold,
            other => other,
        },
        Event::Resume => match status {
            Status::OnHold => Status::Pending,
            other => other,
        },
        Event::Resolve => match status {
            Status::Pending | Status::OnHold => Status::Closed,
            other => other,
        },
    }
}

fn apply_events(mut status: Status, events: &[Event]) -> Status {
    for &event in events {
        status = next_status(status, event);
    }
    status
}

fn label(status: Status) -> &'static str {
    match status {
        Status::Open => "Open",
        Status::Pending => "Pending",
        Status::OnHold => "OnHold",
        Status::Closed => "Closed",
    }
}

fn main() {
    let a = apply_events(Status::Open, &[Event::Assign, Event::Resolve]);
    let b = apply_events(Status::Closed, &[Event::AgentNote]);
    let c = apply_events(Status::Open, &[Event::Assign, Event::PutOnHold, Event::Resolve]);

