const INPUT: &str = r#"
# audit stream v1
2024-05-10T09:15|u01|LOGIN|ok
2024-05-10T09:70|u02|LOGIN|bad minute
2024-05-10T09:20|u-03|LOGOUT|bad user
2024-05-10 09:30|u04|LOGIN|missing T
2024-05-10T09:40|u05|PING|unknown action
2024-05-10T09:45|u06|LOGOUT|ok
2024-05-10T09:46|u07|LOGIN
2024-05-10T09:47|u08|LOGIN|contains|pipe
|u09|LOGIN|missing ts
"#;

fn valid_ts(ts: &str) -> bool {
    if ts.len() != 16 {
        return false;
    }
    let b = ts.as_bytes();
    b[4] == b'-' && b[7] == b'-' && b[10] == b'T' && b[13] == b':'
}

fn valid_user(user: &str) -> bool {
    user.starts_with('u') && user[1..].chars().all(|c| c.is_ascii_digit())
}

fn valid_action(action: &str) -> bool {
    matches!(action, "LOGIN" | "LOGOUT")
}

fn main() {
    let mut accepted = 0usize;
    let mut rejected = 0usize;
    let mut by_user: BTreeMap<String, usize> = BTreeMap::new();

    for raw in INPUT.lines() {
        let line = raw.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }

        let parts: Vec<&str> = line.split('|').collect();
        if parts.len() < 4 {
            rejected += 1;
            continue;
