        let ts = parts[0];
        let user = parts[1];
        let action = parts[2];

        if !valid_user(user) || !valid_action(action) {
            rejected += 1;
            continue;
        }

        if valid_ts(ts) {
            accepted += 1;
            *by_user.entry(user.to_string()).or_insert(0) += 1;
        } else {
            rejected += 1;
        }
    }

    let users = by_user
        .into_iter()
        .map(|(u, n)| format!("{}:{}", u, n))
        .collect::<Vec<_>>()
        .join(",");

    print!(
        "{{\"accepted\":{},\"rejected\":{},\"users\":[{}]}}",
        accepted, rejected, users
    );
}
