    "src/lib.rs": "pub fn parse_record(line: &str) -> Result<Vec<(String, String)>, String> {
    let mut out = Vec::new();
    if line.is_empty() {
        return Err("empty record".to_string());
    }
    for field in line.split(';') {
        let (key, value) = field
            .split_once('=')
            .ok_or_else(|| format!("missing '=' in field: {field}"))?;
        if key.is_empty() {
            return Err("empty key".to_string());
        }
        if value.is_empty() {
            return Err(format!("empty value for key: {key}"));
        }
        if !key.bytes().all(|b| b.is_ascii_lowercase() || b == b'_') {
            return Err(format!("invalid key: {key}"));
        }
        out.push((key.to_string(), value.to_string()));
    }
    Ok(out)
}

pub fn validate_required(fields: &[(String, String)], required: &[&str]) -> Result<(), String> {
    for key in required {
        if !fields.iter().any(|(k, _)| k == key) {
            return Err(format!("missing required key: {key}"));
        }
    }
    Ok(())
}

