    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy, PartialEq, Eq)]
enum Status {
    Ready,
    Running,
    Blocked,
    Done,
}

enum Event<'a> {
    Add(&'a str),
    Start(&'a str),
    Block(&'a str),
    Unblock(&'a str),
    Finish(&'a str),
}

fn main() {
    let events = [
        Event::Add("A"),
        Event::Add("B"),
        Event::Start("A"),
        Event::Add("C"),
        Event::Block("A"),
        Event::Unblock("A"),
        Event::Finish("A"),
        Event::Start("B"),
        Event::Finish("B"),
        Event::Block("C"),
        Event::Add("D"),
        Event::Start("D"),
        Event::Finish("A"),
        Event::Start("C"),
    ];

    let mut items: BTreeMap<&str, Status> = BTreeMap::new();

    for event in events {
        match event {
            Event::Add(id) => {
                items.entry(id).or_insert(Status::Ready);
            }
            Event::Start(id) => {
                if matches!(items.get(id), Some(Status::Ready)) {
                    items.insert(id, Status::Running);
                }
            }
            Event::Block(id) => {
                if matches!(items.get(id), Some(Status::Running)) {
                    items.insert(id, Status::Blocked);
                }
            }
            Event::Unblock(id) => {
                if matches!(items.get(id), Some(Status::Blocked)) {
                    items.insert(id, Status::Ready);
                }
            }
            Event::Finish(id) => {
                if matches!(items.get(id), Some(Status::Running)) {
                    items.insert(id, Status::Done);
                }
            }
        }
    }

    let mut ready = 0;
    let mut running = 0;
    let mut blocked = 0;
    let mut done = 0;

    for status in items.values() {
        match status {
            Status::Ready => ready += 1,
            Status::Running => running += 1,
            Status::Blocked => blocked += 1,
            Status::Done => done += 1,
        }
    }

    println!("ready={} running={} done={} blocked={}", ready, running, done, blocked);

    for (id, status) in items {
        let name = match status {
            Status::Ready => "Ready",
            Status::Running => "Running",
            Status::Blocked => "Blocked",
            Status::Done => "Done",
        };
        println!("{}:{}", id, name);
    }
}
