fn render(alert: &Alert) -> String {
    match alert {
        Alert::Ok(msg) => format!("ok: {}", msg),
        Alert::Warn { code, msg } if *code >= 10 => format!("warn: [{}] {}", code, msg),
        Alert::Warn { .. } => String::from("warn: retrying"),
        Alert::Error(msg) => format!("err: {}", msg),
        Alert::Skip(Some(reason)) => format!("skip: {}", reason),
        Alert::Skip(None) => String::from("skip: no reason"),
    }
}

