    let mut warn = 0;
    let mut err = 0;
    let mut skip = 0;
    let mut lines = Vec::new();

    for alert in &alerts {
        match alert {
            Alert::Ok(_) => ok += 1,
            Alert::Warn { .. } => warn += 1,
            Alert::Error(_) => err += 1,
            Alert::Skip(_) => skip += 1,
        }
        lines.push(render(alert));
    }

